import { useContext, useCallback, useEffect, useState } from "react";
import {
  Button,
  Grid,
  Typography,
  Paper,
  makeStyles,
  TextField,
} from "@material-ui/core";
import axios from "axios";
import ChipInput from "material-ui-chip-input";
import FileUploadInput from "../lib/FileUploadInput";
import DescriptionIcon from "@material-ui/icons/Description";
import FaceIcon from "@material-ui/icons/Face";

import { SetPopupContext } from "../App";
import apiList from "../lib/apiList";

const useStyles = makeStyles(() => ({
  body: { height: "inherit" },
  popupDialog: {
    height: "100%",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },
}));

const MultifieldInput = ({ education, setEducation }) => {
  const classes = useStyles();

  return (
    <>
      {education.map((obj, key) => (
        <Grid item container spacing={2} key={key}>
          <Grid item xs={6}>
            <TextField
              label={`Institution Name #${key + 1}`}
              value={obj.institutionName}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].institutionName = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              fullWidth
            />
          </Grid>
          <Grid item xs={3}>
            <TextField
              label="Start Year"
              value={obj.startYear}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].startYear = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              type="number"
              fullWidth
            />
          </Grid>
          <Grid item xs={3}>
            <TextField
              label="End Year"
              value={obj.endYear}
              onChange={(e) => {
                const newEdu = [...education];
                newEdu[key].endYear = e.target.value;
                setEducation(newEdu);
              }}
              variant="outlined"
              type="number"
              fullWidth
            />
          </Grid>
        </Grid>
      ))}
      <Grid item>
        <Button
          variant="contained"
          color="secondary"
          onClick={() =>
            setEducation([
              ...education,
              {
                institutionName: "",
                startYear: "",
                endYear: "",
              },
            ])
          }
          className={classes.inputBox}
        >
          Add another institution
        </Button>
      </Grid>
    </>
  );
};

const Profile = () => {
  const setPopup = useContext(SetPopupContext);

  const [profileDetails, setProfileDetails] = useState({
    name: "",
    education: [],
    skills: [],
    resume: "",
    profile: "",
  });

  const [education, setEducation] = useState([
    {
      institutionName: "",
      startYear: "",
      endYear: "",
    },
  ]);

  const getData = useCallback(() => {
    axios
      .get(apiList.user, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      })
      .then((res) => {
        setProfileDetails(res.data);

        if (res.data.education?.length > 0) {
          setEducation(
            res.data.education.map((edu) => ({
              institutionName: edu.institutionName || "",
              startYear: edu.startYear || "",
              endYear: edu.endYear || "",
            }))
          );
        }
      })
      .catch((err) => {
        console.error(err.response?.data || "Error fetching profile");
        setPopup({
          open: true,
          severity: "error",
          message: "Failed to fetch profile",
        });
      });
  }, [setProfileDetails, setEducation, setPopup]);

  useEffect(() => {
    getData();
  }, [getData]);

  const handleInput = (key, value) => {
    setProfileDetails((prev) => ({ ...prev, [key]: value }));
  };

  const handleUpdate = () => {
    const updatedDetails = {
      ...profileDetails,
      education: education
        .filter((obj) => obj.institutionName.trim())
        .map(({ institutionName, startYear, endYear }) => {
          const entry = { institutionName, startYear };
          if (endYear.trim()) entry.endYear = endYear;
          return entry;
        }),
    };
    console.log("🔐 Token from localStorage:", localStorage.getItem("token"));

    axios
      .put(apiList.user, updatedDetails, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      })
      .then((res) => {
        setPopup({
          open: true,
          severity: "success",
          message: res.data.message,
        });
        getData();
      })
      .catch((err) => {
        console.error(err.response);
        setPopup({
          open: true,
          severity: "error",
          message: err.response?.data?.message || "Update failed",
        });
      });
  };

  return (
    <Grid
      container
      direction="column"
      alignItems="center"
      style={{ padding: "30px", minHeight: "93vh" }}
    >
      <Grid item>
        <Typography variant="h2">Profile</Typography>
      </Grid>
      <Grid item xs>
        <Paper
          style={{ padding: 20, display: "flex", flexDirection: "column" }}
        >
          <Grid container direction="column" spacing={3}>
            <Grid item>
              <TextField
                label="Name"
                value={profileDetails.name}
                onChange={(e) => handleInput("name", e.target.value)}
                variant="outlined"
                fullWidth
              />
            </Grid>
            <MultifieldInput
              education={education}
              setEducation={setEducation}
            />
            <Grid item>
              <ChipInput
                label="Skills"
                variant="outlined"
                helperText="Press enter to add"
                value={profileDetails.skills}
                onAdd={(chip) =>
                  setProfileDetails((prev) => ({
                    ...prev,
                    skills: [...prev.skills, chip],
                  }))
                }
                onDelete={(chip, idx) => {
                  const newSkills = [...profileDetails.skills];
                  newSkills.splice(idx, 1);
                  setProfileDetails((prev) => ({
                    ...prev,
                    skills: newSkills,
                  }));
                }}
                fullWidth
              />
            </Grid>
            <Grid item>
              <FileUploadInput
                label="Resume (.pdf)"
                icon={<DescriptionIcon />}
                uploadTo={apiList.uploadResume}
                handleInput={handleInput}
                identifier="resume"
              />
            </Grid>
            <Grid item>
              <FileUploadInput
                label="Profile Photo (.jpg/.png)"
                icon={<FaceIcon />}
                uploadTo={apiList.uploadProfileImage}
                handleInput={handleInput}
                identifier="profile"
              />
            </Grid>
          </Grid>
          <Button
            variant="contained"
            color="primary"
            style={{ marginTop: 30 }}
            onClick={handleUpdate}
          >
            Update Details
          </Button>
        </Paper>
      </Grid>
    </Grid>
  );
};

export default Profile;
